// 迷宫 BFS 基本框架
#include <bits/stdc++.h>
using namespace std;

int N, M;
char grid[105][105];
bool vis[105][105];
int dist[105][105];
int dx[] = {-1, 1, 0, 0};
int dy[] = {0, 0, -1, 1};

int bfs(int sx, int sy, int ex, int ey) {
  queue<pair<int,int>> q;
  q.push({sx, sy});
  vis[sx][sy] = true;
  dist[sx][sy] = 0;

  while (!q.empty()) {
    auto [x, y] = q.front();
    q.pop();
    if (x == ex && y == ey) return dist[x][y];

    for (int d = 0; d < 4; d++) {
      int nx = x + dx[d];
      int ny = y + dy[d];
      if (nx>=0 && nx<N && ny>=0 && ny<M
          && !vis[nx][ny] && grid[nx][ny]!='#') {
        vis[nx][ny] = true;
        dist[nx][ny] = dist[x][y] + 1;
        q.push({nx, ny});
      }
    }
  }
  return -1;
}

