#include <bits/stdc++.h>
using namespace std;

const int MAXN = 105;
int N, M;
char grid[MAXN][MAXN];
bool vis[MAXN][MAXN];
int dist[MAXN][MAXN];
pair<int,int> pre[MAXN][MAXN];
int dx[] = {-1, 1, 0, 0};
int dy[] = {0, 0, -1, 1};

int main() {
  cin >> N >> M;
  int sx, sy, ex, ey;
  for (int i = 0; i < N; i++)
    for (int j = 0; j < M; j++) {
      cin >> grid[i][j];
      if (grid[i][j] == 'S') { sx = i; sy = j; }
      if (grid[i][j] == 'E') { ex = i; ey = j; }
    }

  memset(vis, false, sizeof(vis));
  memset(dist, -1, sizeof(dist));
  queue<pair<int,int>> q;
  q.push({sx, sy});
  vis[sx][sy] = true;
  dist[sx][sy] = 0;

  while (!q.empty()) {
    auto [x, y] = q.front(); q.pop();
    for (int d = 0; d < 4; d++) {
      int nx = x + dx[d], ny = y + dy[d];
      if (nx<0||nx>=N||ny<0||ny>=M) continue;
      if (vis[nx][ny] || grid[nx][ny]=='#') continue;
      vis[nx][ny] = true;
      dist[nx][ny] = dist[x][y] + 1;
      pre[nx][ny] = {x, y};
      q.push({nx, ny});
    }
  }

  cout << dist[ex][ey] << endl;
  return 0;
}
